// ==================== FUNÇÕES DE SEGURANÇA ====================

// Sanitizar HTML para prevenir XSS em popups e elementos dinâmicos
const escapeHtml = (text) => {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = String(text);
    return div.innerHTML;
};

// Sanitizar para uso em atributos HTML
const escapeAttr = (text) => {
    if (!text) return '';
    return String(text)
        .replace(/&/g, '&amp;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;');
};

// ==================== FIM FUNÇÕES DE SEGURANÇA ====================

// ==================== SISTEMA DE VERSÃO E CACHE ====================
const APP_VERSION = "2.2.3"; // Security Patch V3 - Refresh Token + Account Lock
const VERSION_KEY = "tutts_app_version";

// Verificar se precisa limpar cache (versão diferente)
(function checkVersion() {
    const savedVersion = localStorage.getItem(VERSION_KEY);
    if (savedVersion !== APP_VERSION) {
        console.log(`🔄 Atualizando de ${savedVersion || 'inicial'} para ${APP_VERSION}`);
        
        // Limpar caches
        if ('caches' in window) {
            caches.keys().then(names => {
                names.forEach(name => {
                    caches.delete(name);
                    console.log(`🗑️ Cache ${name} limpo`);
                });
            });
        }
        
        // Limpar localStorage antigo (exceto dados importantes)
        const keysToKeep = ['tutts_user', VERSION_KEY]; // 🔒 token agora é in-memory
        Object.keys(localStorage).forEach(key => {
            if (!keysToKeep.includes(key) && !key.startsWith('tutts_tutorial')) {
                localStorage.removeItem(key);
            }
        });
        
        // Salvar nova versão
        localStorage.setItem(VERSION_KEY, APP_VERSION);
        
        // Forçar reload se tinha versão anterior (não no primeiro acesso)
        if (savedVersion) {
            console.log('🔄 Recarregando para aplicar atualizações...');
            window.location.reload(true);
        }
    }
})();

// Forçar atualização do Service Worker se existir
if ('serviceWorker' in navigator) {
    navigator.serviceWorker.getRegistrations().then(registrations => {
        registrations.forEach(registration => {
            registration.update();
        });
    });
}

// ==================== FIM SISTEMA DE VERSÃO ====================

// ==================== FUNÇÕES DE AUTENTICAÇÃO ====================

// 🔒 SECURITY FIX (HIGH-01): Token em memória ao invés de sessionStorage
// XSS não consegue ler variável de closure — só sessionStorage/localStorage
let _accessToken = null;

// 🔧 FIX: Timer de refresh proativo
let _refreshTimerId = null;

// Obter token JWT armazenado
const getToken = () => {
    return _accessToken;
};

// Obter refresh token armazenado
const getRefreshToken = () => {
    return null; // 🔒 Refresh token agora está em HttpOnly cookie
};

// Salvar token JWT
const setToken = (token) => {
    _accessToken = token || null;
};

// Salvar refresh token
const setRefreshToken = (refreshToken) => {
    // 🔒 Refresh token agora está em HttpOnly cookie
    // Limpar qualquer resquício do localStorage antigo
    localStorage.removeItem("tutts_refresh_token");
};

// Variável para controlar se está renovando token (evitar múltiplas chamadas)
let isRefreshingToken = false;
let refreshPromise = null;

// 🔧 FIX: Agendar refresh proativo — renova ANTES do token/cookie expirar
// Roda a cada 30 minutos (token dura 8h, cookie dura 8h)
const iniciarRefreshProativo = () => {
    // Limpar timer anterior se existir
    if (_refreshTimerId) {
        clearInterval(_refreshTimerId);
    }
    // Renovar a cada 30 minutos (1800000ms)
    _refreshTimerId = setInterval(async () => {
        const userSalvo = sessionStorage.getItem("tutts_user");
        if (userSalvo && _accessToken) {
            console.log('🔄 Refresh proativo — renovando token...');
            await renovarToken();
        } else {
            // Sem sessão ativa, parar o timer
            clearInterval(_refreshTimerId);
            _refreshTimerId = null;
        }
    }, 30 * 60 * 1000); // 30 minutos
};

// Parar refresh proativo
const pararRefreshProativo = () => {
    if (_refreshTimerId) {
        clearInterval(_refreshTimerId);
        _refreshTimerId = null;
    }
};

// 🔒 SECURITY FIX (HIGH-01): Ao recarregar página, token em memória se perde.
// Restaurar automaticamente via refresh cookie se usuário existir em sessionStorage.
// 🔧 RACE FIX: Promise que resolve quando o bootstrap de auth termina.
// fetchAuth aguarda essa promise antes de qualquer request — impede que
// requests saiam com token null durante a janela de restauração do token.
let _authBootstrapResolver;
const _authBootstrapPromise = new Promise(resolve => { _authBootstrapResolver = resolve; });

(async function restaurarTokenAoCarregar() {
    const userSalvo = sessionStorage.getItem("tutts_user");
    if (userSalvo && !_accessToken) {
        try {
            const response = await fetch(API_URL + '/users/refresh-token', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                credentials: 'include',
                body: JSON.stringify({})
            });
            if (response.ok) {
                const data = await response.json();
                if (data.token) {
                    _accessToken = data.token;
                    // 🔧 FIX: Atualizar CSRF no restore também
                    if (data.csrfToken) {
                        sessionStorage.setItem('tutts_csrf', data.csrfToken);
                    }
                    if (data.user) {
                        sessionStorage.setItem("tutts_user", JSON.stringify(data.user));
                    }
                    console.log('🔄 Token restaurado via refresh cookie');
                    // 🔧 FIX: Iniciar refresh proativo após restaurar sessão
                    iniciarRefreshProativo();
                }
            } else if (response.status === 401 || response.status === 403) {
                // 🔧 BUGFIX F5-DISCONNECT: Só apaga sessão em status de auth explícito.
                // Antes: qualquer !response.ok (incluindo 500, 502, 503, timeout) apagava
                // sessionStorage e o usuário era deslogado em qualquer hiccup de rede/backend.
                console.warn(`⚠️ Refresh cookie inválido (HTTP ${response.status}) — limpando sessão`);
                sessionStorage.removeItem("tutts_user");
                sessionStorage.removeItem("tutts_csrf");
            } else {
                // Erros transitórios (5xx) ou inesperados: mantém sessão, loga e segue.
                // O usuário ainda tem o refresh cookie httpOnly, então fetchAuth nas
                // próximas requests vai tentar renovar de novo e eventualmente funciona.
                console.warn(`⚠️ Refresh falhou com HTTP ${response.status} — mantendo sessão (retry no próximo fetch)`);
            }
        } catch (e) {
            // 🔧 BUGFIX F5-DISCONNECT: Erros de rede NÃO deslogam.
            // Antes passava direto sem tocar em sessionStorage, mas sem restaurar o token
            // em memória também — o que deixava a app num estado estranho.
            // Agora explicita que a sessão fica intacta e será recuperada no próximo fetch.
            console.warn('⚠️ Erro de rede ao restaurar token (mantendo sessão):', e.message);
        }
    }
    // 🔧 RACE FIX: sempre resolve (sucesso OU falha OU sessão ausente)
    _authBootstrapResolver();
})();

// Função para renovar token usando refresh token (via HttpOnly cookie)
const renovarToken = async () => {
    // Se já está renovando, esperar a promise existente
    if (isRefreshingToken && refreshPromise) {
        return refreshPromise;
    }
    
    isRefreshingToken = true;
    
    refreshPromise = (async () => {
        try {
            const response = await fetch(API_URL + '/users/refresh-token', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                credentials: 'include', // 🔒 Envia refresh cookie automaticamente
                body: JSON.stringify({}) // Body vazio — refresh token vai no cookie
            });
            
            if (response.ok) {
                const data = await response.json();
                setToken(data.token);
                // 🔒 Atualizar CSRF token se veio novo
                if (data.csrfToken) {
                    sessionStorage.setItem('tutts_csrf', data.csrfToken);
                }
                if (data.user) {
                    sessionStorage.setItem("tutts_user", JSON.stringify(data.user));
                }
                console.log('🔄 Token renovado automaticamente');
                return data.token;
            } else if (response.status === 401 || response.status === 403) {
                // 🔧 BUGFIX F5-DISCONNECT: Só desloga em 401/403 explícitos (refresh inválido/revogado).
                // 500/502/503/timeout são transitórios — retornar null permite retry mais tarde
                // sem destruir a sessão.
                console.log(`❌ Refresh token inválido (HTTP ${response.status}) — fazendo logout`);
                fazerLogoutCompleto();
                return null;
            } else {
                // Erros transitórios: NÃO desloga, só sinaliza falha pra este ciclo.
                // O próximo fetchAuth com 401 vai tentar renovar de novo.
                console.warn(`⚠️ Renovação falhou transitoriamente (HTTP ${response.status}) — tentando de novo em seguida`);
                return null;
            }
        } catch (error) {
            // 🔧 BUGFIX F5-DISCONNECT: Erro de rede NÃO desloga.
            console.error('❌ Erro de rede ao renovar token (mantendo sessão):', error.message);
            return null;
        } finally {
            isRefreshingToken = false;
            refreshPromise = null;
        }
    })();
    
    return refreshPromise;
};

// Função para fazer logout completo
const fazerLogoutCompleto = () => {
    pararRefreshProativo(); // 🔧 FIX: Parar timer ao deslogar
    sessionStorage.removeItem("tutts_user");
    sessionStorage.removeItem("tutts_social_profile"); // 📸 limpar cache da foto
    _accessToken = null; // 🔒 Limpar token em memória
    sessionStorage.removeItem("tutts_csrf");
    sessionStorage.removeItem("tutts_todo_notif_shown"); // 🔒 Reset flag para próximo login
    localStorage.removeItem("tutts_refresh_token"); // Limpar resquício antigo
    // 🔧 FIX HOME-NO-LOGIN: limpa o último módulo ativo e o estado das abas
    // pra que o próximo login sempre abra na Home, não no último módulo usado.
    try { localStorage.removeItem("tutts_modulo_ativo"); } catch(e) {}
    try { localStorage.removeItem("tutts_abas_estado"); } catch(e) {}
    // 🔧 FIX HOME-NO-LOGIN: redireciona pra raiz (sem hash) em vez de recarregar
    // mantendo a URL atual. Assim F5 logado não cai em tela de módulo direto.
    window.location.href = window.location.origin + window.location.pathname;
};

// Função para fazer requisições autenticadas com auto-refresh
const fetchAuth = async (url, options = {}, retryCount = 0) => {
    // 🔧 RACE FIX: Aguarda o bootstrap de auth terminar antes de disparar
    // qualquer request. Isso impede que um F5 envie fetches com token null
    // enquanto o IIFE restaurarTokenAoCarregar ainda está renovando o token.
    if (_authBootstrapPromise) {
        try { await _authBootstrapPromise; } catch(e) {}
    }
    let token = getToken();
    const headers = {
        'Content-Type': 'application/json',
        ...options.headers
    };
    
    // Header Authorization mantido para WebSocket/iframe compat
    if (token) {
        headers['Authorization'] = `Bearer ${token}`;
    }
    
    // 🔒 CSRF token em mutações (POST, PUT, DELETE, PATCH)
    const method = (options.method || 'GET').toUpperCase();
    if (!['GET', 'HEAD', 'OPTIONS'].includes(method)) {
        // Lê direto do cookie para garantir sincronia com o backend
        const csrfToken = document.cookie.split('; ').find(c => c.startsWith('tutts_csrf='))?.split('=')[1] || sessionStorage.getItem('tutts_csrf');
        if (csrfToken) {
            headers['X-CSRF-Token'] = csrfToken;
        }
    }
    
    try {
        const response = await fetch(url, {
            ...options,
            headers,
            credentials: 'include' // 🔒 Envia cookies HttpOnly automaticamente
        });
        
        // Se token expirou, tentar renovar automaticamente
        if (response.status === 401 && retryCount === 0) {
            const data = await response.clone().json().catch(() => ({}));
            
            if (data.expired) {
                console.log('🔄 Token expirado, tentando renovar...');
                const novoToken = await renovarToken();
                
                if (novoToken) {
                    // Retry com novo token
                    return fetchAuth(url, options, retryCount + 1);
                } else {
                    fazerLogoutCompleto();
                }
            }
        }
        
        // 🔒 FIX: Se CSRF falhou (403), renovar token (que renova CSRF) e retry
        if (response.status === 403 && retryCount === 0) {
            const data = await response.clone().json().catch(() => ({}));
            if (data.error && data.error.toLowerCase().includes('csrf')) {
                console.log('🔄 CSRF inválido, renovando token + CSRF...');
                const novoToken = await renovarToken();
                if (novoToken) {
                    return fetchAuth(url, options, retryCount + 1);
                } else {
                    fazerLogoutCompleto();
                }
            }
        }
        
        return response;
    } catch (error) {
        console.error('Erro na requisição:', error);
        throw error;
    }
};

// ==================== FIM FUNÇÕES DE AUTENTICAÇÃO ====================

// Função helper para verificar permissões de módulo
// Retorna true se o usuário tem acesso ao módulo
function hasModuleAccess(user, moduleId) {
    if (!user) return false;
    
    // Admin master tem acesso a tudo
    if (user.role === "admin_master") return true;
    
    // Admin financeiro tem acesso apenas ao financeiro e solicitações
    if (user.role === "admin_financeiro") {
        return ["financeiro", "solicitacoes", "disponibilidade", "crm-whatsapp"].includes(moduleId);
    }
    
    // User comum tem acesso ao módulo de filas (para check-in na fila)
    if (user.role === "user") {
        return ["filas", "agente", "coleta"].includes(moduleId);
    }
    
    // Admin normal - verificar permissões
    if (user.role === "admin") {
        // Se não tem permissões configuradas, dar acesso a tudo
        if (!user.permissions) return true;
        
        // Se hasConfig é false, significa que nunca foi configurado
        if (user.permissions.hasConfig === false) return true;
        
        // Se não existe o objeto modulos, dar acesso total
        if (!user.permissions.modulos) return true;
        
        // Verificar permissão específica do módulo
        const perm = user.permissions.modulos[moduleId];
        
        // Se hasConfig é true (permissões foram configuradas pelo admin_master),
        // módulo só é permitido se explicitamente true
        if (user.permissions.hasConfig === true) {
            return perm === true;
        }
        
        // Fallback: se nunca foi configurado, tem acesso a tudo
        return perm !== false;
    }
    
    return false;
}

// Função helper para encontrar a primeira aba permitida de um módulo
function getFirstAllowedTab(user, moduleId, defaultTab) {
    if (!user) return defaultTab;
    
    // Admin master tem acesso a tudo
    if (user.role === "admin_master") return defaultTab;
    
    // Encontrar configuração do módulo
    const moduloConfig = SISTEMA_MODULOS_CONFIG.find(m => m.id === moduleId);
    if (!moduloConfig || !moduloConfig.abas) return defaultTab;
    
    // Se não tem permissões de abas configuradas, retorna o default
    const abas = user.permissions && user.permissions.abas ? user.permissions.abas : {};
    if (Object.keys(abas).length === 0) return defaultTab;
    
    // Procurar primeira aba permitida
    for (let i = 0; i < moduloConfig.abas.length; i++) {
        const aba = moduloConfig.abas[i];
        const abaKey = moduleId + "_" + aba.id.replace("-", "");
        if (abas[abaKey] !== false) {
            return aba.id;
        }
    }
    
    // Se nenhuma aba permitida, retorna o default
    return defaultTab;
}

